#define MAX 100
int stack[MAX], top = -1;

void push(int value) {
    if (top == MAX - 1) { printf("Overflow\n"); return; }
    stack[++top] = value;
}

int pop() {
    if (top == -1) { printf("Underflow\n"); return -1; }
    return stack[top--];
}

// Example: 5 6 2 + * = 5 * (6+2) = 40
// Scan: push 5, push 6, push 2, see '+' -> pop 2,6 -> push 8
// see '*' -> pop 8,5 -> push 40 -> result on top of stack
